mapper.select:

where conversation_id = #{conversationId}
  and user_id = #{userId}
order by message_id asc

select *
from (

    where conversation_id = #{conversationId}
      and user_id = #{userId}
    order by message_id desc
    limit #{limit}
) t
order by t.message_id asc

mapper.delete:
delete from ai_message
where conversation_id = #{conversationId}
  and user_id = #{userId}
